# Getting Started

Wraps the application with DndContext to enable dnd-kit hooks like useDraggable and useDroppable. Requires @dnd-kit/core.

```jsx
import React from 'react';
import {DndContext} from '@dnd-kit/core';
import {Draggable} from './Draggable';
import {Droppable} from './Droppable';

function App() {
  return (
    <DndContext>
      <Draggable />
      <Droppable />
    </DndContext>
  );
}
```

**Category:** Getting Started
**URL:** https://next.dndkit.com/legacy/introduction/getting-started

# Basic Sortable List

Implement a basic sortable vertical list using dnd-kit.

```jsx
import React, {useState} from 'react';
import {DndContext, closestCenter, KeyboardSensor, PointerSensor, useSensor, useSensors} from '@dnd-kit/core';
import {arrayMove, SortableContext, sortableKeyboardCoordinates, verticalListSortingStrategy} from '@dnd-kit/sortable';
import {SortableItem} from './SortableItem';

function App() {
  const [items, setItems] = useState([1, 2, 3]);
  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {coordinateGetter: sortableKeyboardCoordinates})
  );

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={items} strategy={verticalListSortingStrategy}>
        {items.map((id) => <SortableItem key={id} id={id} />)}
      </SortableContext>
    </DndContext>
  );

  function handleDragEnd(event) {
    const {active, over} = event;
    if (active.id !== over.id) {
      setItems((items) => {
        const oldIndex = items.indexOf(active.id);
        const newIndex = items.indexOf(over.id);
        return arrayMove(items, oldIndex, newIndex);
      });
    }
  }
}
```

**Category:** Presets
**URL:** https://next.dndkit.com/legacy/presets/sortable/overview

# DragOverlay with Ref Forwarding

Use DragOverlay to render a custom drag preview. Separate the sortable logic from the overlay's rendered content to avoid ID collisions.

```jsx
import React, {useState} from 'react';
import {closestCenter, DndContext, DragOverlay, KeyboardSensor, PointerSensor, useSensor, useSensors} from '@dnd-kit/core';
import {arrayMove, SortableContext, sortableKeyboardCoordinates, verticalListSortingStrategy} from '@dnd-kit/sortable';
import {SortableItem} from './SortableItem';
import {Item} from './Item';

function App() {
  const [activeId, setActiveId] = useState(null);
  const [items, setItems] = useState(['1', '2', '3']);
  const sensors = useSensors(useSensor(PointerSensor), useSensor(KeyboardSensor, {coordinateGetter: sortableKeyboardCoordinates}));

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
      <SortableContext items={items} strategy={verticalListSortingStrategy}>
        {items.map((id) => <SortableItem key={id} id={id} />)}
      </SortableContext>
      <DragOverlay>{activeId ? <Item id={activeId} /> : null}</DragOverlay>
    </DndContext>
  );
}
```

The Item component must use forwardRef:
```jsx
export const Item = forwardRef(({id, ...props}, ref) => {
  return <div {...props} ref={ref}>{id}</div>;
});
```

**Category:** Presets
**URL:** https://next.dndkit.com/legacy/presets/sortable/overview

# useSortable Hook

The useSortable hook combines useDraggable and useDroppable. It provides attributes, listeners, node referencing, transform, and transition properties.

```jsx
import React from 'react';
import {useSortable} from '@dnd-kit/sortable';
import {CSS} from '@dnd-kit/utilities';

function SortableItem(props) {
  const {attributes, listeners, setNodeRef, transform, transition} = useSortable({id: props.id});
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
      ...
    </div>
  );
}
```

**Category:** API
**URL:** https://next.dndkit.com/legacy/presets/sortable

# useDraggable and useDroppable with Data

Use the `data` argument to define type for droppable areas and supports for draggable items, enabling conditional dropping.

```jsx
import {DndContext, useDraggable, useDroppable} from '@dnd-kit/core';

function Droppable() {
  const {setNodeRef} = useDroppable({
    id: 'droppable',
    data: { type: 'type1' },
  });
  /* ... */
}

function Draggable() {
  const {attributes, listeners, setNodeRef, transform} = useDraggable({
    id: 'draggable',
    data: { supports: ['type1', 'type2'] },
  });
  /* ... */
}

function App() {
  return <DndContext onDragEnd={handleDragEnd}>/* ... */</DndContext>;

  function handleDragEnd(event) {
    const { active, over } = event;
    if (over && active.data.current.supports.includes(over.data.current.type)) {
      // do stuff
    }
  }
}
```

**Category:** API
**URL:** https://next.dndkit.com/legacy/api-documentation/draggable/use-draggable

# Multiple Droppable Containers

Manage drag and drop between multiple containers.

```jsx
import React, {useState} from 'react';
import {DndContext} from '@dnd-kit/core';
import {Droppable} from './Droppable';
import {Draggable} from './Draggable';

function App() {
  const containers = ['A', 'B', 'C'];
  const [parent, setParent] = useState(null);
  const draggableMarkup = <Draggable id="draggable">Drag me</Draggable>;

  return (
    <DndContext onDragEnd={handleDragEnd}>
      {parent === null ? draggableMarkup : null}
      {containers.map((id) => (
        <Droppable key={id} id={id}>
          {parent === id ? draggableMarkup : 'Drop here'}
        </Droppable>
      ))}
    </DndContext>
  );

  function handleDragEnd(event) {
    const {over} = event;
    setParent(over ? over.id : null);
  }
}
```

**Category:** Getting Started
**URL:** https://next.dndkit.com/legacy/introduction/getting-started

# Multiple Drag Handles

A single draggable item can have multiple designated drag handles.

```jsx
import {useDraggable} from '@dnd-kit/core';

function Draggable() {
  const {attributes, listeners, setNodeRef} = useDraggable({ id: 'unique-id' });

  return (
    <div ref={setNodeRef}>
      <button {...listeners} {...attributes}>Drag handle 1</button>
      {/* Some other content */}
      <button {...listeners} {...attributes}>Drag handle 2</button>
    </div>
  );
}
```

**Category:** API
**URL:** https://next.dndkit.com/legacy/api-documentation/draggable/use-draggable

# Sensors Configuration

Configure sensors for keyboard and pointer interactions.

```jsx
import {DndContext, KeyboardSensor, PointerSensor, useSensor, useSensors} from '@dnd-kit/core';
import {SortableContext, sortableKeyboardCoordinates} from '@dnd-kit/sortable';

function App() {
  const [items] = useState(['1', '2', '3']);
  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  return (
    <DndContext sensors={sensors}>
      <SortableContext items={items}>{/* ... */}</SortableContext>
    </DndContext>
  );
}
```

Available sensors: PointerSensor, KeyboardSensor, TouchSensor, MouseSensor.
Collision detection algorithms: closestCenter, closestCorners, rectIntersection, pointerWithin.

**Category:** API
**URL:** https://next.dndkit.com/legacy/presets/sortable

# DndContext API Reference

DndContext is the root provider for drag and drop functionality. Props: children, sensors (SensorDescriptor[]), collisionDetection (CollisionDetection), modifiers (Modifiers), autoScroll (boolean), screenReaderInstructions, announcements, cancelDrop.

Event handlers:
- onDragStart(DragStartEvent) - fires when drag begins
- onDragMove(DragMoveEvent) - fires during drag movement
- onDragOver(DragOverEvent) - fires when dragging over a droppable
- onDragEnd(DragEndEvent) - fires when drag completes
- onDragCancel() - fires when drag is cancelled

onDragEnd provides active.id and over.id (null if no collision). Events provide information only - consumers must update state.

```jsx
<DndContext
  sensors={sensors}
  collisionDetection={closestCenter}
  modifiers={[restrictToWindowEdges]}
  onDragStart={(event) => console.log('started', event.active.id)}
  onDragEnd={(event) => handleDragEnd(event.active.id, event.over?.id)}
  onDragCancel={() => setActiveId(null)}
>
  {children}
</DndContext>
```

# useDndMonitor Hook

Monitor drag and drop events from any child component within DndContext. Must be used inside DndContext provider.

```jsx
import {DndContext, useDndMonitor} from '@dnd-kit/core';

function MyComponent() {
  useDndMonitor({
    onDragStart(event) { console.log('started', event); },
    onDragMove(event) { console.log('moved', event); },
    onDragOver(event) { console.log('over', event); },
    onDragEnd(event) { console.log('ended', event); },
    onDragCancel(event) { console.log('cancelled', event); },
  });
  return <div>Monitoring...</div>;
}

function App() {
  return (
    <DndContext onDragEnd={handleDragEnd}>
      <MyComponent />
    </DndContext>
  );
}
```

useDndMonitor receives the same event objects as DndContext handlers, enabling event monitoring in child components without prop drilling.

# DragDropProvider - New React API

The new @dnd-kit/react API provides DragDropProvider as replacement for DndContext with explicit plugin architecture.

```jsx
import {DragDropProvider, PointerSensor, KeyboardSensor} from '@dnd-kit/react';
import {RestrictToWindow} from '@dnd-kit/modifiers';

function App() {
  return (
    <DragDropProvider
      sensors={[PointerSensor, KeyboardSensor]}
      modifiers={[RestrictToWindow]}
    >
      <YourDraggableContent />
    </DragDropProvider>
  );
}
```

DragDropProvider simplifies setup by:
- Accepting sensor classes directly (not SensorDescriptor[])
- Auto-configuring collision detection
- Built-in accessibility and announcements
- Plugin-based modular architecture

Note: This is the new recommended API in @dnd-kit/react. Legacy API uses DndContext from @dnd-kit/core.
